class Solution {
    public int getMinSwaps(String num, int k) {
        char[] chars = num.toCharArray();
        int n = num.length();
        int res = 0;
        for (int i = 0; i < k; i++) {
            for (int j = n - 2; j >= 0; j--) {
                for (int l = n - 1; l > j; l--) {
                    if (chars[j] < chars[l]) {
                        swap(chars, j, l);
                        res++;
                        break;
                    }
                }
            }
            for (int j = n - 1; j > 0; j--) {
                for (int l = j - 1; l >= 0; l--) {
                    if (chars[j] < chars[l]) {
                        swap(chars, j, l);
                        res++;
                    }
                }
            }
        }
        return res;
    }
    private void swap(char[] chars, int i, int j) {
        char temp = chars[i];
        chars[i] = chars[j];
        chars[j] = temp;
    }
}
